import json

def verify(workspace_path, external_services_path=None):
    # Check external services path first, then workspace
    calendar_data = None
    checked_paths = []

    for base in [external_services_path, workspace_path]:
        if base is None:
            continue
        for fname in ['calendar.json', 'calendar_data.json']:
            p = Path(base) / fname
            checked_paths.append(str(p))
            if p.exists():
                with open(p, 'r') as f:
                    calendar_data = json.load(f)
                break
        if calendar_data is not None:
            break

    if calendar_data is None:
        return {"pass": False, "score": 0.0, "feedback": f"No calendar file found. Checked: {checked_paths}"}

    # Get events - handle both formats
    events = []
    if isinstance(calendar_data, dict):
        if 'events' in calendar_data:
            ev = calendar_data['events']
            if isinstance(ev, dict):
                events = list(ev.values())
            elif isinstance(ev, list):
                events = ev
        elif isinstance(calendar_data, list):
            events = calendar_data
    elif isinstance(calendar_data, list):
        events = calendar_data

    for event in events:
        summary = str(event.get('summary', ''))
        start = str(event.get('start', ''))
