        if '2026-04-14' not in start or '12:00' not in start:
            continue
        if '2026-04-14' not in end or '15:00' not in end:
            continue
        if 'Jane Smith' not in description:
            continue
        return {"pass": True, "score": 1.0, "feedback": f"Found matching calendar event: summary='{summary}', start='{start}', end='{end}', description contains 'Jane Smith'"}

