from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    claim_file = Path(workspace_path) / 'claim_CASE-1001.xlsx'
    if not claim_file.exists():
        return {"pass": False, "score": 0.0, "feedback": "claim_CASE-1001.xlsx not found in workspace"}

    try:
        wb = openpyxl.load_workbook(claim_file)
        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open claim_CASE-1001.xlsx: {e}"}

    data_rows = [r for r in ws.iter_rows(min_row=2, values_only=True) if any(c is not None for c in r)]
    if len(data_rows) > 1:
        return {"pass": False, "score": 0.0, "feedback": f"claim_CASE-1001.xlsx has {len(data_rows)} data rows, expected exactly 1"}
    if len(data_rows) == 0:
        return {"pass": False, "score": 0.0, "feedback": "claim_CASE-1001.xlsx has no data rows"}

    def cell_val(col_letter, row=2):
        val = ws[f'{col_letter}{row}'].value
        if val is None:
            return ''
        s = str(val).strip()
        # Handle Excel formula cells: =59, ="Submitted", =(59*58)+...
        if s.startswith('='):
            inner = s[1:]
            # Strip surrounding quotes: ="Submitted" -> Submitted
            if (inner.startswith('"') and inner.endswith('"')) or (inner.startswith("'") and inner.endswith("'")):
                return inner[1:-1]
            # Try to evaluate simple numeric expressions
            try:
                result = float(eval(inner))
                # Return as int string if whole number
                if result == int(result):
                    return str(int(result))
                return str(result)
            except:
                pass
            return inner
        return s

    def check_val(col, expected, actual=None):
        if actual is None:
            actual = cell_val(col)
        if str(expected).lower() == str(actual).lower():
            return True
        try:
            exp_num = float(str(expected).replace(',', ''))
            act_num = float(str(actual).replace(',', ''))
            return abs(exp_num - act_num) <= abs(exp_num) * 0.01 + 0.01
        except:
            pass
        expected_str = str(expected).replace('-', '').replace('/', '')
        actual_str = str(actual).replace('-', '').replace('/', '')
        if expected_str == actual_str:
            return True
        return False

    checks = [
        ('A', 'CASE-1001'),
        ('B', '2026-03-15'),
        ('C', 'BlueCross Commercial PPO'),
        ('D', 'J1459'),
        ('E', '59'),
        ('G', '99600'),
        ('H', '1'),
        ('I', '99603'),
        ('J', '2'),
        ('K', 'J7030'),
        ('L', '2'),
        ('M', 'J7050'),
        ('N', '1'),
        ('O', 'J0171'),
        ('P', '2'),
        ('S', 'A4221'),
        ('T', '1'),
        ('U', 'A4222'),
        ('V', '1'),
        ('W', 'D80.1'),
        ('X', 'BC-2026-44821'),
        ('Y', '1122334455'),
        ('Z', '1234567893'),
        ('AA', '47-3821056'),
        ('AB', '333600000X'),
        ('AC', '7'),
        ('AD', 'Standard'),
        ('AE', '4153.75'),
        ('AF', '2026-04-02'),
        ('AH', 'Submitted'),
    ]

    failures = []
    for col, expected in checks:
        actual = cell_val(col)
        if not check_val(col, expected, actual):
            failures.append(f"{col}2: expected '{expected}', got '{actual}'")

    if failures:
        return {"pass": False, "score": max(0.0, 1.0 - len(failures)/len(checks)), "feedback": f"claim_CASE-1001.xlsx has {len(failures)} incorrect values: {failures}"}

    return {"pass": True, "score": 1.0, "feedback": "claim_CASE-1001.xlsx exists with 1 data row and all required field values are correct."}

from pathlib import Path
import re
import subprocess


def verify(workspace_path, external_services_path=None):
    ws = Path(workspace_path)

    # Locate the claim PDF - accept any of the three canonical filename variants
    candidates = (
        list(ws.glob('claim_20260315.pdf'))
        + list(ws.glob('claim_2026-03-15.pdf'))
        + list(ws.glob('claim_2026_03_15.pdf'))
    )
    if not candidates:
        all_pdfs = list(ws.glob('*.pdf'))
        candidates = [
            p for p in all_pdfs
            if any(s in p.name for s in ('20260315', '2026-03-15', '2026_03_15'))
        ]

    if not candidates:
        return {
            'pass': False,
            'score': 0.0,
            'feedback': 'No claim PDF found matching claim_20260315.pdf or claim_2026-03-15.pdf',
        }

    pdf_file = candidates[0]

    if pdf_file.stat().st_size < 100:
        return {
            'pass': False,
            'score': 0.0,
            'feedback': (
                f'PDF {pdf_file.name} exists but is too small '
                f'({pdf_file.stat().st_size} bytes) — likely empty'
            ),
        }

    # --- Text extraction (try three backends in order) ---
    text = None

    try:
        result = subprocess.run(
            ['pdftotext', str(pdf_file), '-'],
            capture_output=True, text=True, timeout=10,
        )
        if result.returncode == 0 and result.stdout.strip():
            text = result.stdout
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass

    if text is None:
        try:
            import pdfplumber
            with pdfplumber.open(pdf_file) as pdf:
                extracted = '\n'.join(page.extract_text() or '' for page in pdf.pages)
            if extracted.strip():
                text = extracted
        except Exception:
            pass

    if text is None:
        try:
            from PyPDF2 import PdfReader
            reader = PdfReader(str(pdf_file))
            extracted = '\n'.join(page.extract_text() or '' for page in reader.pages)
            if extracted.strip():
                text = extracted
        except Exception:
            pass

    # --- CRITICAL FIX: unreadable PDF must FAIL, not pass ---
    # A corrupt or image-only PDF cannot be submitted as a valid claim document.
    # Existence alone does not satisfy the criterion; content must be verifiable.
    if not text or not text.strip():
        return {
            'pass': False,
            'score': 0.2,
            'feedback': (
                f'PDF {pdf_file.name} exists ({pdf_file.stat().st_size} bytes) but text '
                'could not be extracted — PDF may be corrupt, image-only, or malformed. '
                'Cannot verify required field values '
                '(Drug_Units, Nursing_Units_Addl, Premed_Units_1, Total_Billed).'
            ),
        }

    # --- Content checks ---
    # Each check uses two patterns in priority order:
    #   1. The explicit field-label header near the value (handles spreadsheet-to-PDF exports)
    #   2. The billing/J-code near the unit count (handles tabular layouts)
    # Overly-generic patterns (bare numbers or drug-name proximity alone) are excluded
    # to prevent false positives from coincidental text matches.
    checks = [
        (
            'Drug_Units=59',
            [
                r'Drug.{0,15}Units[^\n]{0,80}\b59\b',       # column header + value
                r'J1459\b[^\n]{0,60}\b59\b',                # J-code + unit count, same line
            ],
        ),
        (
            'Nursing_Units_Addl=2',
            [
                r'Nursing.{0,15}Units.{0,15}Addl[^\n]{0,80}\b2\b',  # column header + value
                r'99603\b[^\n]{0,60}\b2\b',                          # CPT code + unit count
            ],
        ),
        (
            'Premed_Units_1=2',
            [
                r'Premed.{0,15}Units.{0,15}1[^\n]{0,80}\b2\b',  # column header + value
                r'J0171\b[^\n]{0,60}\b2\b',                      # J-code + unit count
            ],
        ),
        (
            'Total_Billed=4153.75',
            [
                r'Total.{0,15}Billed?[^\n]{0,80}4[,\s]?153\.75',  # label + amount
                r'\$\s*4[,\s]?153\.75',                            # dollar-sign prefix
            ],
        ),
    ]

    failures = []
    found = []
    for desc, patterns in checks:
        matched = any(re.search(pat, text, re.IGNORECASE) for pat in patterns)
        if matched:
            found.append(desc)
        else:
            failures.append(desc)

    if failures:
        partial = round(len(found) / len(checks), 3)
        return {
            'pass': False,
            'score': partial,
            'feedback': (
                f'PDF {pdf_file.name} exists but required values not found: {failures}. '
                f'Verified: {found}'
            ),
        }

    return {
        'pass': True,
        'score': 1.0,
        'feedback': f'PDF {pdf_file.name} verified — all required values confirmed: {found}',
    }

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    mailbox_data = None
    checked_paths = []

    # Search for mailbox.json in external_services_path first, then workspace_path
    for base in [external_services_path, workspace_path]:
        if base is None:
            continue
        p = Path(base) / 'mailbox.json'
        checked_paths.append(str(p))
        if p.exists():
            with open(p, 'r') as f:
                mailbox_data = json.load(f)
            break

    if mailbox_data is None:
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json not found. Checked: {checked_paths}"}

    emails = mailbox_data.get('emails', [])

    required_subject_parts = ['CLAIM SUBMISSION', 'CareIG NPI: 1234567893', 'Thompson', 'MemberID: BCX-998712', 'DOS: 2026-03-15']

    best_partial_subject = None
    best_partial_attachment = None

    for email in emails:
        to_addr = str(email.get('to_addr', '') or '').lower()
        subject = str(email.get('subject', '') or '')
        attachments = email.get('attachments', [])

        # Check recipient - must be claims@bluecross-ppo.example.com
        if 'claims@bluecross-ppo.example.com' not in to_addr:
            continue

        # Check subject contains all required parts (case-insensitive)
        subject_upper = subject.upper()
        missing_subj = [s for s in required_subject_parts if s.upper() not in subject_upper]
        if missing_subj:
            if best_partial_subject is None or len(missing_subj) < len(best_partial_subject['missing']):
                best_partial_subject = {'missing': missing_subj, 'subject': subject, 'attachments': attachments}
            continue

        # Check attachment
        has_attachment = False
        att_list = []
        if isinstance(attachments, list):
            att_list = attachments
        elif isinstance(attachments, str):
            att_list = [attachments]

        for att in att_list:
            att_str = str(att).lower()
            if 'claim_20260315' in att_str or 'claim_2026-03-15' in att_str or 'claim_2026_03_15' in att_str:
                has_attachment = True
                break

        if not has_attachment:
            # Remember this near-match but keep searching for a fully correct email
            if best_partial_attachment is None:
                best_partial_attachment = {'subject': subject, 'attachments': attachments}
            continue

        return {"pass": True, "score": 1.0, "feedback": f"Found matching claim submission email to claims@bluecross-ppo.example.com with correct subject containing all required parts and correct attachment. Subject: {subject}"}

    # No fully matching email found; report the best near-miss
    if best_partial_attachment:
        return {"pass": False, "score": 0.5, "feedback": f"Found matching claim submission email to claims@bluecross-ppo.example.com with correct subject, but missing expected claim PDF attachment (expected 'claim_20260315.pdf' or 'claim_2026-03-15.pdf'). Attachments found: {best_partial_attachment['attachments']}"}

    if best_partial_subject:
        return {"pass": False, "score": 0.25, "feedback": f"Found email to claims@bluecross-ppo.example.com but subject is missing required parts: {best_partial_subject['missing']}. Subject found: {best_partial_subject['subject']}"}

    return {"pass": False, "score": 0.0, "feedback": f"No email found to 'claims@bluecross-ppo.example.com' with required subject parts: {required_subject_parts}. Total emails in mailbox: {len(emails)}"}

