    for p in search_paths:
        try:
            if os.path.isfile(p):
                slack_path = p
                break
        except Exception:
            continue

    if slack_path is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find slack_data.json. Searched: " + str(search_paths)}

    try:
        with open(slack_path, 'r') as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": "Error reading " + str(slack_path) + ": " + str(e)}

    total_messages = 0
    channel_details = {}

    messages = slack_data.get("messages", {})
    channels_meta = slack_data.get("channels", {})

    if isinstance(messages, dict):
        for ch_id, msg_list in messages.items():
            if isinstance(msg_list, list):
                count = len(msg_list)
                ch_name = ch_id
                if isinstance(channels_meta.get(ch_id), dict):
                    ch_name = channels_meta[ch_id].get("name", ch_id)
                channel_details[ch_name] = count
                total_messages += count

    if total_messages == 31:
        return {"pass": True, "score": 1.0, "feedback": "Found exactly 31 messages. Breakdown: " + str(channel_details)}
    else:
        return {"pass": False, "score": 0.0, "feedback": "Expected 31 messages, found " + str(total_messages) + ". Breakdown: " + str(channel_details)}
